sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    try {
        var body = request.body.data;

        // Basic validation
        if (!body || !body.short_description || !body.u_originated_from || !body.xurrent_imr_incident
                || !body.urgency_sys_id || !body.state_sys_id || !body.entity_type_sys_id || !body.mandatory_fields) {
            response.setStatus(400);
            return {
                status: "error",
                message: "Missing required fields: short_description, u_originated_from, xurrent_imr_incident, urgency_sys_id, state_sys_id, entity_type_sys_id, mandatory_fields"
            };
        }

        // ── Resolve urgency value from sys_id ─────────────────────────────────
        var urgencyGR = new GlideRecord('sys_choice');
        urgencyGR.addQuery('name', 'task');
        urgencyGR.addQuery('element', 'urgency');
        urgencyGR.addQuery('sys_id', body.urgency_sys_id);
        urgencyGR.query();
        if (!urgencyGR.next()) {
            response.setStatus(404);
            return {
                status: "error",
                message: "Incident urgency not found with sys_id: " + body.urgency_sys_id
            };
        }
        var urgencyValue = urgencyGR.value;

        // ── Resolve state value from sys_id ───────────────────────────────────
        var stateGR = new GlideRecord('sys_choice');
        stateGR.addQuery('name', 'incident');
        stateGR.addQuery('element', 'state');
        stateGR.addQuery('sys_id', body.state_sys_id);
        stateGR.query();
        if (!stateGR.next()) {
            response.setStatus(404);
            return {
                status: "error",
                message: "Incident state not found with sys_id: " + body.state_sys_id
            };
        }
        var stateValue = stateGR.value;

        // ── Resolve priority value from sys_id (optional) ─────────────────────
        var snowPriority = null;
        if (body.snow_priority_sys_id) {
            var priorityGR = new GlideRecord('sys_choice');
            priorityGR.addQuery('name', 'incident');
            priorityGR.addQuery('element', 'priority');
            priorityGR.addQuery('sys_id', body.snow_priority_sys_id);
            priorityGR.query();
            if (priorityGR.next()) {
                snowPriority = priorityGR.value;
            }
        }

        // ── Step 1: Fetch entity type from sys_db_object ──────────────────────
        var sysDbGR = new GlideRecord('sys_db_object');
        sysDbGR.addQuery('sys_id', body.entity_type_sys_id);
        sysDbGR.query();
        if (!sysDbGR.next()) {
            response.setStatus(404);
            return {
                status: "error",
                message: "Entity type not found in sys_db_object with sys_id: " + body.entity_type_sys_id
            };
        }
        var entityTableName = sysDbGR.getValue('name');       // actual table name e.g. 'sys_user_group'
        var entityFieldName = sysDbGR.getDisplayValue('name'); // label / display value e.g. 'assignment_group'

        // ── Step 2: Resolve entity record sys_id ──────────────────────────────
        var entityRecordSysId = null;
        var CUSTOM_MODE     = 2;
        var NAME_MATCH_MODE = 1;

		// ── Validate mode-specific required fields ─────────────────────────────
        if (body.entity_type_mapping_mode == NAME_MATCH_MODE && !body.service_name) {
            response.setStatus(400);
            return {
                status: "error",
                message: "service_name is required when entity_type_mapping_mode is name_match"
            };
        }
        if (body.entity_type_mapping_mode == CUSTOM_MODE && !body.entity_record_sys_id) {
            response.setStatus(400);
            return {
                status: "error",
                message: "entity_record_sys_id is required when entity_type_mapping_mode is custom"
            };
        }

        if (body.entity_type_mapping_mode == CUSTOM_MODE) {
            var recordGR = new GlideRecord(entityTableName);
			if (recordGR.get(body.entity_record_sys_id)) {
				entityRecordSysId = recordGR.getUniqueValue();
			} else {
				response.setStatus(404);
				return {
					status: "error",
					message: "Entity record not found with sys_id: " + body.entity_record_sys_id + " in table: " + entityTableName
				};
			}
        } else if (body.entity_type_mapping_mode == NAME_MATCH_MODE) {
            var displayField = new GlideTableDescriptor(entityTableName).getDisplayField();
			var nameMatchGR = new GlideRecord(entityTableName);
			nameMatchGR.addQuery(displayField, body.service_name);
			nameMatchGR.query();
			if (nameMatchGR.next()) {
				entityRecordSysId = nameMatchGR.getUniqueValue();
			} else {
				response.setStatus(404);
				return {
					status: "error",
					message: "Entity record not found for service_name: " + body.service_name + " in table: " + entityTableName
				};
			}
        }

        // ── Create incident ───────────────────────────────────────────────────
        var incident = new GlideRecord('incident');
        incident.initialize();
        incident.short_description      = body.short_description;
        incident.description            = body.description;
        incident.u_originated_from      = body.u_originated_from;
        incident.u_xurrent_imr_incident = body.xurrent_imr_incident;
        incident.urgency                = urgencyValue;
        incident.state                  = stateValue;

        if (snowPriority) { incident.priority = snowPriority; }

        if (entityFieldName && entityRecordSysId) {
            incident.setValue(entityFieldName, entityRecordSysId);
        }

        incident.caller_id = gs.getUser().getID();

        // Set mandatory fields
        for (var field in body.mandatory_fields) {
            incident.setValue(field, body.mandatory_fields[field]);
        }

        var sysId = incident.insert();

        gs.info("Incident created successfully");
        response.setStatus(201);
        return {
            status:  "success",
            message: "Incident created",
            sys_id:  sysId,
            number:  incident.number.toString()
        };

    } catch (err) {
        gs.error("Incident creation failed: " + err.message);
        response.setStatus(400);
        return {
            status:  "error",
            message: err.message
        };
    }

})(request, response);
